const returns = $input.all();

const statusLabels = {
  'created': 'Utworzone',
  'received': 'Otrzymane',
  'refunded': 'Zwrócono środki',
  'rejected': 'Odrzucone'
};

const formattedReturns = returns.map(r => {
  let items = r.json.items;
  if (typeof items === 'string') {
    try {
      items = JSON.parse(items);
    } catch (e) {
      items = [];
    }
  }

  return {
    id: r.json.id,
    order_id: r.json.order_id,
    order_number: r.json.order_number,
    customer_name: r.json.customer_name,
    email: r.json.email,
    reason: r.json.reason,
    items: items,
    status: r.json.status,
    status_label: statusLabels[r.json.status] || r.json.status,
    created_at: r.json.created_at,
    updated_at: r.json.updated_at
  };
});

return [{
  json: {
    returns: formattedReturns,
    total: formattedReturns.length
  }
}];
